arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;

var builder = WebApplication.CreateBuilder(args);

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView allData = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age), nameof(CustomerData.Income), "RegionEncoded", nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(CustomerData.Churned)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"))
    .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

var model = pipeline.Fit(split.TrainSet);

var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromUri(modelName: "ChurnModel",
        uri: string.Empty, // not used — we load from the trained model below
        period: TimeSpan.Zero);

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, allData.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelName: "ChurnModel", filePath: modelPath, watchForChanges: false);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API is running");

app.MapPost("/predict", (CustomerData input,
    Microsoft.Extensions.ML.PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict("ChurnModel", input);
    return Results.Ok(new
    {
        prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = string.Empty;
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")] public string Churned { get; set; } = string.Empty;
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = string.Empty;
    public float Probability { get; set; }
    public float Score { get; set; }
}

